@Pipe({
    name: 'sentenceToWord',
})
export class SentenceToWordPipe implements PipeTransform {
    public transform(value: string | null | undefined): string[] {
        if(!value) {
            return [];
        }
        
        return value.split(' ');
    }
}`},{name:"SizeDisplayPipe",id:"pipe-SizeDisplayPipe-c4d08ce716dbe87ae218c72923837981373a49d99e1984b59634234e7cbecab456aedfead757b71d0936a63d1ec4ee5cd9025171a7e1a662589143b1a854205a",file:"projects/irrtirer/src/app/core/pipes/size-display.pipe.ts",type:"pipe",deprecated:!1,deprecationMessage:"",description:"",rawdescription:`
